package com.shecancode.notification.controller; import com.shecancode.notification.model.Notification; import com.shecancode.notification.repo.NotificationRepository; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/notifications") public class NotificationController { private final NotificationRepository repo; public NotificationController(NotificationRepository r){repo=r;} @PostMapping public Notification create(@RequestBody Notification n){return repo.save(n);} @GetMapping("/user/{userId}") public List<Notification> list(@PathVariable Long userId){return repo.findByUserIdOrderByCreatedAtDesc(userId);} @PatchMapping("/{id}/read") public Notification read(@PathVariable Long id){Notification n=repo.findById(id).orElseThrow();n.setReadFlag(true);return repo.save(n);} @DeleteMapping("/{id}") public void delete(@PathVariable Long id){repo.deleteById(id);} }